args.sparql:
SELECT ?winner ?winnerLabel
WHERE {
  ?ceremony wdt:P31 wd:Q5022837;  # award ceremony
          wdt:P166 wd:Q1137234;  # part of CMA Awards
          wdt:P571 ?date.
  ?ceremony wdt:P1326 ?winner.  # winner of the ceremony
  SERVICE wikidata:label { bd:serviceParam wikidata:language "en". }
  }
ORDER BY DESC(?date)
LIMIT 1

SELECT ?winner ?winnerLabel
WHERE {
  ?ceremony wdt:P166 wd:Q1137234;
          wdt:P571 ?date.
  ?ceremony p:P1326 [
    ps:P1326 ?winner;
    pq:P1619 ?category
  ].
  ?category rdfs:label "Entertainer of the Year"@en.
  ?winner rdfs:label ?winnerLabel.
  FILTER (LANG(?winnerLabel) = 'en').
}
ORDER BY DESC(?date)
LIMIT 1
